import React, { useState } from "react";
import { BrowserRouter, Routes, Route, useNavigate } from "react-router-dom";
import "./App.css";

function Login() {
  const navigate = useNavigate();

  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");

  const [emailError, setEmailError] = useState("");
  const [passwordError, setPasswordError] = useState("");

  const validateLogin = () => {
    let valid = true;

    setEmailError("");
    setPasswordError("");

    const emailPattern =
      /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

    if (!email) {
      setEmailError("Email is required");
      valid = false;
    } else if (!emailPattern.test(email)) {
      setEmailError("Enter valid email with @");
      valid = false;
    }

    if (!password) {
      setPasswordError("Password is required");
      valid = false;
    } else if (password.length < 6) {
      setPasswordError(
        "Password must be at least 6 characters"
      );
      valid = false;
    }

    if (valid) {
      alert("Login Successful");
    }
  };

  return (
    <div className="page">
      <div className="phone-card">
        <div className="top-shape"></div>

        <h1>Welcome</h1>

        <p className="subtitle">
          Sign in to continue
        </p>

        <div className="form">
          <label>Email</label>

          <input
            type="text"
            placeholder="your email address goes here"
            value={email}
            onChange={(e) =>
              setEmail(e.target.value)
            }
          />

          {emailError && (
            <p className="error">
              {emailError}
            </p>
          )}

          <label>Password</label>

          <input
            type="password"
            placeholder="••••••••"
            value={password}
            onChange={(e) =>
              setPassword(e.target.value)
            }
          />

          {passwordError && (
            <p className="error">
              {passwordError}
            </p>
          )}

          <p
            className="forgot"
            onClick={() =>
              navigate("/forgot-password")
            }
          >
            Forgot Password?
          </p>

          <button onClick={validateLogin}>
            Sign in
          </button>

          <p className="or">OR</p>

          <p>Connect with</p>

          <div className="socials">
            G | f
          </div>

          <p className="bottom-text">
            Don’t have Account?{" "}
            <span
              onClick={() =>
                navigate("/register")
              }
            >
              Sign up
            </span>
          </p>
        </div>
      </div>
    </div>
  );
}

function Register() {
  const navigate = useNavigate();

  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [phone, setPhone] = useState("");
  const [password, setPassword] =
    useState("");

  const [errors, setErrors] = useState(
    {}
  );

  const validateRegister = () => {
    let newErrors = {};

    const emailPattern =
      /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

    if (!name) {
      newErrors.name =
        "Name is required";
    }

    if (!email) {
      newErrors.email =
        "Email is required";
    } else if (
      !emailPattern.test(email)
    ) {
      newErrors.email =
        "Enter valid email with @";
    }

    if (!phone) {
      newErrors.phone =
        "Phone number required";
    } else if (
      !/^[0-9]+$/.test(phone)
    ) {
      newErrors.phone =
        "Only numbers allowed";
    }

    if (!password) {
      newErrors.password =
        "Password required";
    } else if (
      password.length < 6
    ) {
      newErrors.password =
        "Minimum 6 characters";
    }

    setErrors(newErrors);

    if (
      Object.keys(newErrors).length === 0
    ) {
      alert("Registration Successful");
    }
  };

  return (
    <div className="page">
      <div className="phone-card">

        <div
          className="back-button"
          onClick={() => navigate("/")}
        >
          ← Back
        </div>

        <div className="top-shape"></div>

        <h1>Create Account</h1>

        <div className="form">
          <label>Name</label>

          <input
            type="text"
            placeholder="your full name goes here"
            value={name}
            onChange={(e) =>
              setName(e.target.value)
            }
          />

          {errors.name && (
            <p className="error">
              {errors.name}
            </p>
          )}

          <label>Email</label>

          <input
            type="text"
            placeholder="your email address goes here"
            value={email}
            onChange={(e) =>
              setEmail(e.target.value)
            }
          />

          {errors.email && (
            <p className="error">
              {errors.email}
            </p>
          )}

          <label>Phone</label>

          <input
            type="text"
            placeholder="your phone number here"
            value={phone}
            onChange={(e) =>
              setPhone(e.target.value)
            }
          />

          {errors.phone && (
            <p className="error">
              {errors.phone}
            </p>
          )}

          <label>Password</label>

          <input
            type="password"
            placeholder="••••••••"
            value={password}
            onChange={(e) =>
              setPassword(e.target.value)
            }
          />

          {errors.password && (
            <p className="error">
              {errors.password}
            </p>
          )}

          <button
            onClick={validateRegister}
          >
            Sign up
          </button>

          <p className="or">OR</p>

          <p>Create account with</p>

          <div className="socials">
            G | f
          </div>

          <p className="bottom-text">
            Already Have an account?{" "}
            <span
              onClick={() =>
                navigate("/")
              }
            >
              Sign in
            </span>
          </p>
        </div>
      </div>
    </div>
  );
}

function ForgotPassword() {
  const navigate = useNavigate();

  return (
    <div className="page">
      <div className="phone-card">

        <div
          className="back-button"
          onClick={() => navigate("/")}
        >
          ← Back
        </div>

        <div className="top-shape"></div>

        <h1>Reset Password</h1>

        <p className="subtitle">
          Enter your email to reset password
        </p>

        <div className="form">
          <label>Email</label>

          <input
            type="email"
            placeholder="your email address goes here"
          />

          <button>
            Send Reset Link
          </button>

          <p className="bottom-text">
            Remember password?{" "}
            <span
              onClick={() => navigate("/")}
            >
              Sign in
            </span>
          </p>
        </div>
      </div>
    </div>
  );
}

function App() {
  return (
    <BrowserRouter>
      <Routes>
        <Route
          path="/"
          element={<Login />}
        />

        <Route
          path="/register"
          element={<Register />}
        />

        <Route
          path="/forgot-password"
          element={
            <ForgotPassword />
          }
        />
      </Routes>
    </BrowserRouter>
  );
}

export default App;
